INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("青空の下で謁見", 5118061, 20063115, "ペコリーヌとの出会い", 2834, 8, "フリーマーケット会場", 2, 10118, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 40, 7, 1, 0, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("未来の騎空団\nマスコット？", 5118062, 20063115, "マホとの出会い", 2835, 8, "フリーマーケット会場", 2, 10118, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 40, 7, 1, 0, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("お嬢さまからの\n緊急依頼", 5118063, 20063115, "アキノとの出会い", 2837, 8, "ランドソル市街地", 2, 10118, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 40, 7, 1, 0, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("黄金色の悩みごと", 5118064, 20063115, "ジュンとの出会い", 4108402, 8, "フリーマーケット会場", 2, 10118, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 40, 18, 1, 0, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("白熱！　格闘大会！", 5118065, 20063115, "カオリとの出会い", 4107402, 8, "フリーマーケット会場", 2, 10118, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 40, 18, 1, 0, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("祭り太鼓はオーエドの華", 5118066, 20063115, "ニノンとの出会い", 9000227, 8, "オーエド町", 2, 10118, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 40, 16, 1, 1, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("人気者は遅れて\nやってくる", 5118067, 20063115, "スズナとの出会い", 2101181, 8, "フリーマーケット会場", 3, 10118, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 40, 19, 1, 0, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("巫女・ミーツ・魔法少女", 5118068, 20063115, "ナナカとの出会い", 4109402, 8, "ランドソル市街地", 3, 10118, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 40, 18, 1, 0, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ネズ耳は二度なくなる", 5118069, 20063115, "キャル＆コッコロとの出会い", 4305402, 8, "フリーマーケット会場", 3, 10118, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 40, 18, 1, 0, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("この出会いにカンパイ！", 5118070, 20063115, "ユカリとの出会い", 4101402, 8, "ランドソル市街地", 3, 10118, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 40, 18, 1, 0, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("陰陽アンサンブル", 5118071, 20063115, "アオイとの出会い", 4106402, 8, "ランドソル市街地", 3, 10118, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 40, 18, 1, 0, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("運試し十番勝負！", 5118072, 20063115, "シノブとの出会い", 2836, 8, "フリーマーケット会場", 3, 10118, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 40, 7, 1, 1, 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("彼女たちの新たな日常", 5118600, 20063115, "オープニング", 0, 0, 0, 1, 10118, 0, 0, 0, 0, 0, 0);
